export default class FileService {
    /**
     * Determines whether the provided file path exists and has allow-read permissions
     * @param filePath
     */
    static canRead(filePath: string): Promise<boolean>;
    /**
     * Get's a files property declarations lines (declare | public)
     * @param filePath
     */
    static readDeclarations(filePath: string): Promise<{
        definitions: string[];
        fileLines: string[];
    }>;
}
